    with open(QAGENT_CONTEXT_PATH, "r", encoding="utf-8") as f:
        content = f.read()

    required_sections = [
        "## 1. Visão Geral do Projeto",
        "## 2. Stack Tecnológica",
        "## 3. Estrutura do Projeto",
        "## 4. Regras de Arquitetura",
        "## 5. Regras de Teste",
